fn appendSnapshotPrelude(out: *std.ArrayList(u8), allocator: std.mem.Allocator, relative_path: []const u8) !void {
    const dirname = std.fs.path.dirname(relative_path) orelse ".";
    const basename = std.fs.path.basename(relative_path);
    const snapshot_basename = try std.fmt.allocPrint(allocator, "{s}.snap", .{basename});
    defer allocator.free(snapshot_basename);
    const snapshot_path = try std.fs.path.join(allocator, &.{
        "packages/runtime/test/bun-corpus",
        dirname,
        "__snapshots__",
        snapshot_basename,
    });
    defer allocator.free(snapshot_path);

    var threaded = std.Io.Threaded.init(allocator, .{});
    defer threaded.deinit();
    const io = threaded.io();
    const snapshot_source = Io.Dir.cwd().readFileAlloc(io, snapshot_path, allocator, std.Io.Limit.limited(4 * 1024 * 1024)) catch |err| switch (err) {
        error.FileNotFound => return,
        error.NotDir => return,
        else => return err,
    };
    defer allocator.free(snapshot_source);

    try out.appendSlice(allocator, "globalThis.__home_snapshot_values = __home_load_snapshots(");
    try appendJsStringLiteral(out, allocator, snapshot_source);
    try out.appendSlice(allocator, ");\nglobalThis.__home_snapshot_counts = Object.create(null);\n");
}

fn sourceShebangLen(source: []const u8) usize {
    if (!std.mem.startsWith(u8, source, "#!")) return 0;
    const newline = std.mem.indexOfScalar(u8, source, '\n') orelse return source.len;
    return newline + 1;
}

fn appendImportMetaReplacement(
    out: *std.ArrayList(u8),
    allocator: std.mem.Allocator,
    source: []const u8,
    idx: usize,
) !?usize {
    const replacements = [_]struct {
        needle: []const u8,
        replacement: []const u8,
    }{
        .{ .needle = "const __filename = fileURLToPath(import.meta.url);", .replacement = "" },
        .{ .needle = "const __dirname = dirname(__filename);", .replacement = "" },
        .{ .needle = "const __dirname = import.meta.dirname;", .replacement = "" },
        .{ .needle = "const { file } = import.meta;", .replacement = "const file = __filename;" },
        .{ .needle = "const { path, dir, dirname, filename } = import.meta;", .replacement = "const path = __home_import_meta_path;\nconst dir = __home_import_meta_dir;\nconst dirname = __home_import_meta_dirname;\nconst filename = __filename;" },
        .{ .needle = "var { require } = import.meta;", .replacement = "var require = globalThis.__home_require;" },
        .{ .needle = "import.meta.resolveSync", .replacement = "__home_import_meta_resolve" },
        .{ .needle = "import.meta.resolve", .replacement = "__home_import_meta_resolve" },
        .{ .needle = "import.meta.dirname", .replacement = "__home_import_meta_dirname" },
        .{ .needle = "import.meta.dir", .replacement = "__home_import_meta_dir" },
        .{ .needle = "import.meta.filename", .replacement = "__filename" },
        .{ .needle = "import.meta.file", .replacement = "__filename" },
        .{ .needle = "import.meta.path", .replacement = "__home_import_meta_path" },
        .{ .needle = "import.meta.url", .replacement = "\"file:///\" + __home_import_meta_path" },
    };

    for (replacements) |entry| {
        if (std.mem.startsWith(u8, source[idx..], entry.needle)) {
            try out.appendSlice(allocator, entry.replacement);
            return idx + entry.needle.len;
        }
    }
    return null;
}

fn rewriteImportMeta(allocator: std.mem.Allocator, source: []const u8) ![]u8 {
    var out = std.ArrayList(u8).empty;
    defer out.deinit(allocator);

    const Mode = enum { code, single_quote, double_quote, template, line_comment, block_comment };
    var mode: Mode = .code;
    var i: usize = 0;
    while (i < source.len) {
        const byte = source[i];
        switch (mode) {
            .code => {
                if (try appendImportMetaReplacement(&out, allocator, source, i)) |next| {
                    i = next;
                    continue;
                }
                if (byte == '\'') mode = .single_quote;
                if (byte == '"') mode = .double_quote;
                if (byte == '`') mode = .template;
                if (byte == '/' and i + 1 < source.len and source[i + 1] == '/') mode = .line_comment;
                if (byte == '/' and i + 1 < source.len and source[i + 1] == '*') mode = .block_comment;
                try out.append(allocator, byte);
                i += 1;
            },
            .single_quote, .double_quote, .template => {
                const terminator: u8 = switch (mode) {
                    .single_quote => '\'',
                    .double_quote => '"',
                    .template => '`',
                    else => unreachable,
                };
                try out.append(allocator, byte);
                if (byte == '\\' and i + 1 < source.len) {
                    i += 1;
                    try out.append(allocator, source[i]);
                } else if (mode == .template and byte == '$' and i + 1 < source.len and source[i + 1] == '{') {
                    const expression_end_after_brace = skipTemplateExpressionForModuleSyntax(source, i + 2);
                    if (expression_end_after_brace > i + 2 and expression_end_after_brace <= source.len and source[expression_end_after_brace - 1] == '}') {
                        try out.append(allocator, '{');
                        const rewritten_expression = try rewriteImportMeta(allocator, source[i + 2 .. expression_end_after_brace - 1]);
                        defer allocator.free(rewritten_expression);
                        try out.appendSlice(allocator, rewritten_expression);
                        try out.append(allocator, '}');
                        i = expression_end_after_brace - 1;
                    }
                } else if (byte == terminator) {
                    mode = .code;
                }
                i += 1;
            },
            .line_comment => {
                try out.append(allocator, byte);
                if (byte == '\n') mode = .code;
                i += 1;
            },
            .block_comment => {
                try out.append(allocator, byte);
                if (byte == '*' and i + 1 < source.len and source[i + 1] == '/') {
                    i += 1;
                    try out.append(allocator, source[i]);
                    mode = .code;
                }
                i += 1;
            },
        }
    }
    return out.toOwnedSlice(allocator);
}

