        \\  const child = spawn(bunExe(), ["-e", 'process.stdout.write("testing\\n");'], {
        \\    env: bunEnv,
        \\    stdio: ["pipe", "pipe", "pipe"],
        \\  });
        \\  child.stdout.destroy();
