test "bootstrap runner mirrors grpc frame-size corpus" {
    if (!build_options.enable_jsc) return error.SkipZigTest;

    const source =
        \\import { afterAll, beforeAll, describe, test } from "bun:test";
        \\import assert from "node:assert";
