        \\    const { parentPort } = require("worker_threads");
        \\    parentPort.on("message", msg => {
        \\      const port = msg.ports[0];
        \\      port.on("message", data => port.postMessage({ reply: "Got: " + data.text }));
        \\      parentPort.postMessage({ ready: true });
