        \\  );
        \\});
        \\
        \\test("partialDeepStrictEqual with Map - should fail when expected has more keys", () => {
        \\  assert.throws(
        \\    () =>
        \\      assert.partialDeepStrictEqual(
        \\        new Map([["key1", "value1"]]),
        \\        new Map([
